import React, { useEffect, useState } from "react";
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import SavingsDepositScreen from "./screens/SavingsDepositScreen";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen";
import TransactionsScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import AddMoneyOptionsScreen from "./screens/AddMoneyOptionsScreen";
import PaymentProcessingScreen from "./screens/PaymentProcessingScreen";
import PaymentSuccessScreen from "./screens/PaymentSuccessScreen";
import ProfileScreen from "./screens/ProfileScreen";
import GoalsScreen from "./screens/GoalsScreen";
import LoansScreen from "./screens/LoansScreen";
import SignInScreen from "./screens/SignInScreen";
import SignUpScreen from "./screens/SignUpScreen";
import BottomNav from "./components/BottomNav";
import { generateReference } from "./helpers/reference";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("SignIn");
  const [balance, setBalance] = useState(0);
  const [savingsBalance, setSavingsBalance] = useState(0);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [user, setUser] = useState({ name: "Pips", email: "pips@example.com", joinedDate: new Date() });
  const [darkMode, setDarkMode] = useState(false);
  const [activeTab, setActiveTab] = useState("home");

  /* =======================
     LOAD FROM LOCAL STORAGE
  ======================== */
  useEffect(() => {
    const storedBalance = localStorage.getItem("balance");
    const storedSavings = localStorage.getItem("savingsBalance");
    const storedTransactions = localStorage.getItem("transactions");
    const storedDarkMode = localStorage.getItem("darkMode");

    if (storedBalance) setBalance(Number(storedBalance));
    if (storedSavings) setSavingsBalance(Number(storedSavings));
    if (storedTransactions) setTransactions(JSON.parse(storedTransactions));
    if (storedDarkMode) setDarkMode(storedDarkMode === "true");
  }, []);

  /* =======================
     SAVE TO LOCAL STORAGE
  ======================== */
  useEffect(() => {
    localStorage.setItem("balance", balance);
    localStorage.setItem("savingsBalance", savingsBalance);
    localStorage.setItem("transactions", JSON.stringify(transactions));
    localStorage.setItem("darkMode", darkMode);
  }, [balance, savingsBalance, transactions, darkMode]);

  const goHome = () => {
    setCurrentScreen("Home");
    setActiveTab("home");
  };

  const openScreen = (screen, data = null) => {
    if (screen === "TransactionReceipt") setSelectedTransaction(data);
    setCurrentScreen(screen);
  };

  const handleLogout = () => setCurrentScreen("SignIn");

  const handleSignIn = (userData) => {
    setUser({ ...userData, joinedDate: new Date() });
    goHome();
  };

  const handleSignUp = (userData) => {
    setUser({ ...userData, joinedDate: new Date() });
    goHome();
  };

  return (
    <div className={darkMode ? "dark" : ""}>
      {/* GLOBAL DARK MODE CLASSES */}
      <div className={`min-h-screen ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>
        {/* Dark Mode Toggle */}
        {currentScreen !== "SignIn" && currentScreen !== "SignUp" && (
  <div className="fixed top-5 right-5 z-50">
    <button
      onClick={() => setDarkMode(!darkMode)}
      className="p-2 rounded-full bg-gray-200 dark:bg-gray-700 transition"
    >
      {darkMode ? <Sun className="w-5 h-5 text-yellow-400" /> : <Moon className="w-5 h-5 text-gray-800 dark:text-gray-200" />}
    </button>
  </div>
)}

        {/* SCREENS */}
        {currentScreen === "SignIn" && <SignInScreen onSignIn={handleSignIn} />}
        {currentScreen === "SignUp" && <SignUpScreen onSignUp={handleSignUp} />}

        {currentScreen === "Home" && activeTab === "home" && (
          <HomeScreen
            balance={balance}
            savingsBalance={savingsBalance}
            transactions={transactions}
            userName={user.name}
            openScreen={openScreen}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "Deposit" && (
          <DepositScreen
            onDeposit={(amount) => {
              if (amount <= 0) return;
              setBalance(balance + amount);
              setTransactions([
                {
                  id: Date.now(),
                  reference: generateReference(),
                  title: "Deposit",
                  amount,
                  type: "deposit",
                  date: new Date().toDateString(),
                },
                ...transactions,
              ]);
              goHome();
            }}
            onBack={goHome}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "Withdraw" && (
          <WithdrawScreen
            onWithdraw={(amount) => {
              if (amount <= 0) return;
              if (amount > balance) return alert("Insufficient balance");
              setBalance(balance - amount);
              setTransactions([
                {
                  id: Date.now(),
                  title: "Withdrawal",
                  amount,
                  type: "withdraw",
                  date: new Date().toDateString(),
                },
                ...transactions,
              ]);
              goHome();
            }}
            onBack={goHome}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "SavingsDeposit" && (
          <SavingsDepositScreen
            onSave={(amount) => {
              if (amount <= 0) return;
              if (amount > balance) return alert("Insufficient balance");
              setBalance(balance - amount);
              setSavingsBalance(savingsBalance + amount);
              goHome();
            }}
            onBack={goHome}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "SavingsWithdraw" && (
          <SavingsWithdrawScreen
            onWithdraw={(amount) => {
              if (amount <= 0) return;
              if (amount > savingsBalance) return alert("Insufficient savings");
              setSavingsBalance(savingsBalance - amount);
              setBalance(balance + amount);
              goHome();
            }}
            onBack={goHome}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "Transactions" && (
          <TransactionsScreen
            transactions={transactions}
            onSelectTransaction={(tx) => openScreen("TransactionReceipt", tx)}
            onBack={goHome}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "TransactionReceipt" && (
          <TransactionReceiptScreen
            transaction={selectedTransaction}
            onBack={() => openScreen("Transactions")}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "AddMoneyOptions" && (
          <AddMoneyOptionsScreen
            onBack={goHome}
            onSelectOption={(opt) => alert(`Selected ${opt.title}`)}
            darkMode={darkMode}
          />
        )}

        {currentScreen === "PaymentProcessing" && (
          <PaymentProcessingScreen onBack={goHome} darkMode={darkMode} />
        )}

        {currentScreen === "PaymentSuccess" && (
          <PaymentSuccessScreen transaction={transactions[0]} onBack={goHome} darkMode={darkMode} />
        )}

        {currentScreen === "Profile" && (
          <ProfileScreen user={user} onLogout={handleLogout} darkMode={darkMode} />
        )}

        {currentScreen === "Goals" && (
          <GoalsScreen goals={[]} darkMode={darkMode} />
        )}

        {currentScreen === "Loans" && (
          <LoansScreen loans={[]} darkMode={darkMode} />
        )}

        {/* BOTTOM NAV */}
        {currentScreen !== "SignIn" && currentScreen !== "SignUp" && (
          <BottomNav active={activeTab} setActive={(tab) => {
            setActiveTab(tab);
            setCurrentScreen(tab.charAt(0).toUpperCase() + tab.slice(1));
          }} />
        )}
      </div>
    </div>
  );
}
